var e=[{id:`L2_1`,type:`dialog`,speaker:`AGENT_GRONIA_NULL_NULL`,text:{KOREA:` 으음……!`,JPN:` う～ん……！`,ENG:`Mmm...!`,TWN:`嗯……！`},stage:{bg:`TRAIL`,slots:{L:null,C:{char_id:`AGENT_GRONIA_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L3_1`,type:`dialog`,speaker:`AGENT_GRONIA_NULL_NULL`,text:{KOREA:` 하아, 개운하다. 저절로 기지개가 켜지네.`,JPN:` はぁ、すっきりした。身体がすごく休まった感じ。`,ENG:`Haa. Refreshing. Nothing like stretching after waking up.`,TWN:`哈～真舒服，忍不住伸起懶腰呢。`},stage:{bg:`TRAIL`,slots:{L:null,C:{char_id:`AGENT_GRONIA_NULL_NULL`,face:`UNIT_LAUGH`},R:null}}},{id:`L4_1`,type:`dialog`,speaker:`AGENT_GRONIA_NULL_NULL`,text:{KOREA:` 열차 여행도 좋은걸. 이 시간까지 늘어져라 잘 수도 있고.`,JPN:` 列車の旅も悪くないわね。こんな時間までゆっくり眠れるし。`,ENG:`Traveling by train isn't too bad. I can sleep until however late I want.`,TWN:`火車旅行很不錯，還可以睡到現在。`},stage:{bg:`TRAIL`,slots:{L:null,C:{char_id:`AGENT_GRONIA_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L5_1`,type:`dialog`,speaker:`AGENT_GRONIA_NULL_NULL`,text:{KOREA:` 생각해 보면 가뜩이나 요즘 피곤한 일이 많긴 했지. `,JPN:` そういえば、ここのところ面倒くさい仕事ばかりだったよな。 `,ENG:`Hmm, but it's been pretty tough recently.`,TWN:`回想起來，這陣子真的很辛苦，`},stage:{bg:`TRAIL`,slots:{L:null,C:{char_id:`AGENT_GRONIA_NULL_NULL`,face:`UNIT_DESPAIR`},R:null}}},{id:`L6_1`,type:`dialog`,speaker:`AGENT_GRONIA_NULL_NULL`,text:{KOREA:` 육체적으로나, 정신적으로나.`,JPN:` 肉体的にも、精神的にも。`,ENG:`Physically and mentally.`,TWN:`無論是在精神上或是肉體上都是。`},stage:{bg:`TRAIL`,slots:{L:null,C:{char_id:`AGENT_GRONIA_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L7_1`,type:`dialog`,speaker:`AGENT_GRONIA_NULL_NULL`,text:{KOREA:` 그런데 분위기가 조금 묘한걸.`,JPN:` でも何だか変な雰囲気ね。`,ENG:`But the atmosphere here is a little eerie.`,TWN:`不過感覺有點奇妙。`},stage:{bg:`TRAIL`,slots:{L:{char_id:`AGENT_GRONIA_NULL_NULL`,face:`UNIT_IDLE`},C:null,R:null}}},{id:`L8_1`,type:`dialog`,speaker:`AGENT_GRONIA_NULL_NULL`,text:{KOREA:` 이 객차에 있는 사람이 나 혼자뿐이었나?`,JPN:` この客車って私一人しかいなかったっけ？`,ENG:`Was I the only one in this passenger car?`,TWN:`這節車廂裡只有我一位乘客嗎？`},stage:{bg:`TRAIL`,slots:{L:{char_id:`AGENT_GRONIA_NULL_NULL`,face:`UNIT_IDLE`},C:null,R:null}}},{id:`L9_1`,type:`dialog`,speaker:`AGENT_GRONIA_NULL_NULL`,text:{KOREA:` 게다가…… 아까부터 같은 풍경이 계속 반복되는 것 같아.`,JPN:` それに……さっきから同じような景色ばかりが流れているような。`,ENG:`And... I feel like I'm seeing the same view over and over again.`,TWN:`而且……從好像沿路都是相同的景色。`},stage:{bg:`TRAIL`,slots:{L:{char_id:`AGENT_GRONIA_NULL_NULL`,face:`UNIT_SURPRISE`},C:null,R:null}}},{id:`L11_1`,type:`dialog`,speaker:`AGENT_GRONIA_NULL_NULL`,text:{KOREA:` 기분 탓인가? 아니면…….`,JPN:` 私の気のせい？　それとも……`,ENG:`Am I just imagining things? Or...`,TWN:`是我太累嗎？還是……`},stage:{bg:`TRAIL`,slots:{L:null,C:{char_id:`AGENT_GRONIA_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L14_1`,type:`dialog`,speaker:`QM_MARK_ANY_NOIMAGE`,text:{KOREA:` 손님, 도움이 필요하십니까?`,JPN:` お客様、何かお困りでしょうか？`,ENG:`Dear guest, are you in need of assistance?`,TWN:`小姐，請問你需要什麼嗎？`},stage:{bg:`TRAIL`,slots:{L:null,C:{char_id:`AGENT_GRONIA_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L15_1`,type:`dialog`,speaker:`AGENT_GRONIA_NULL_NULL`,text:{KOREA:` 아. 별거 아니에요.`,JPN:` あ、いいえ、大したことじゃないんですけど。`,ENG:`Oh. It's nothing.`,TWN:`喔，沒什麼。`},stage:{bg:`TRAIL`,slots:{L:null,C:{char_id:`AGENT_GRONIA_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L16_1`,type:`dialog`,speaker:`AGENT_GRONIA_NULL_NULL`,text:{KOREA:` 혹시 여기가 어딘지 알 수 있을까요?`,JPN:` 今ここって、どのあたりなんですか？`,ENG:`I'd just like to know where we are.`,TWN:`請問這裡是哪裡？`},stage:{bg:`TRAIL`,slots:{L:null,C:{char_id:`AGENT_GRONIA_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L18_1`,type:`dialog`,speaker:`QM_MARK_ANY_NOIMAGE`,text:{KOREA:` 손님이 선택한 결말입니다.`,JPN:` 「お客様自身が選んだ結末」ですよ。`,ENG:`We are at the ending of your choice.`,TWN:`這裡是你選擇的結局。`},stage:{bg:`TRAIL`,slots:{L:null,C:{char_id:`AGENT_GRONIA_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L19_1`,type:`dialog`,speaker:`AGENT_GRONIA_NULL_NULL`,text:{KOREA:` 네?`,JPN:` え？`,ENG:`Excuse me?`,TWN:`什麼？`},stage:{bg:`TRAIL`,slots:{L:null,C:{char_id:`AGENT_GRONIA_NULL_NULL`,face:`UNIT_SURPRISE`},R:null}}},{id:`L21_1`,type:`dialog`,speaker:`MEMBER_HARMONY_NULL_NULL`,text:{KOREA:` 대답이 되었──`,JPN:` 答えになりました──`,ENG:`I hope that was–`,TWN:`這樣有回答到──`},stage:{bg:`TRAIL`,slots:{L:null,C:{char_id:`AGENT_GRONIA_NULL_NULL`,face:`UNIT_SURPRISE`},R:null}}},{id:`L23_1`,type:`dialog`,speaker:`MEMBER_HARMONY_NULL_NULL`,text:{KOREA:` ──습니. 까.`,JPN:` ──でしょう。か。`,ENG:`–A. Satisfactory. Answer.`,TWN:` ──你的問題嗎？`},stage:{bg:`TRAIL`,slots:{L:null,C:{char_id:`MEMBER_HARMONY_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L26_1`,type:`dialog`,speaker:`AGENT_GRONIA_NULL_NULL`,text:{KOREA:` 하아, 하아…….`,JPN:` はぁ、はぁ……`,ENG:`*Huff, huff...*`,TWN:`呼呼，呼呼……`},stage:{bg:`TRAIL`,slots:{L:null,C:{char_id:`AGENT_GRONIA_NULL_NULL`,face:`UNIT_HATE`},R:null}}}];export{e as default};